async function main() {
  console.log('Start seeding ICD-10 codes...');
  
  for (const c of icd10Data) {
    await prisma.icd10Code.upsert({
      where: { code: c.code },
      update: {},
      create: c,
    });
  }

  console.log(`Seeded ${icd10Data.length} ICD-10 codes successfully.`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
